DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PCCmacros.pl", "contextCurrency.pl", "contextPercent.pl", "parserLinearRelation.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $name = randomPerson(); $profession = list_random( 'a radiography technician', 'a microelectronics engineer', 'a dental hygienist', 'a high school teacher', 'an office manager', 'a restaurant manager', 'a web designer', 'a tax accountant', 'a paralegal', 'a structural engineer' ); Context("Currency")->flags->set(trimTrailingZeros => 1); $final = 65000 + random(-8000,8000); $current = Currency($final); Context("Percent"); $decimal = random(0.02,0.06,0.001); $percent = Percent($decimal); Context("LinearRelation")->variables->are(S => 'Real'); $equation = LinearRelation("S + $decimal S = $final");
############################################################ # Body ############################################################
BEGIN_PGML Read the scenario. Then write a complete sentence that defines a variable to use. Lastly, write an equation to model the scenario. There is no need to solve the equation.
[$name]'s current annual salary as [$profession] is [`[$current]\text{.}`] This is with a raise of [`[$percent]`] over last year's salary. What was [$name->possessive] salary last year? Set up an equation to answer this question. There is no need to solve it.
[@KeyboardInstructions('Use [|S|]* as the variable.')@]**
[_]{$equation}{20}
END_PGML
